def create_shelter_groups(apps, schema_editor):
    from shelters.models import (
        SPA,
        Accessibility,
        City,
        ContactInfo,
        Demographic,
        EntryRequirement,
        ExitPolicy,
        ExteriorPhoto,
        Funder,
        InteriorPhoto,
        MediaLink,
        Parking,
        Pet,
        ReferralRequirement,
        RoomStyle,
        Schedule,
        Service,
        ServiceCategory,
        Shelter,
        ShelterProgram,
        ShelterType,
        SpecialSituationRestriction,
        Storage,
        Video,
    )
    from shelters.utils import assign_permissions_to_group_in_migration

    from common.models import Address

    shared_models = [
        Accessibility, City, ContactInfo, Demographic, EntryRequirement,
        ExitPolicy, ExteriorPhoto, Funder, InteriorPhoto, MediaLink,
        Parking, Pet, ReferralRequirement, RoomStyle, Schedule,
        Service, ServiceCategory, ShelterProgram, ShelterType, SPA,
        SpecialSituationRestriction, Storage, Video,
    ]

    shared_permission_map = {model: [model.perms] for model in shared_models}
    shared_permission_map[Address] = [Address.perms]

    # Shelter Data Entry: CRUD only (no custom perms)
    data_entry_permission_map = dict(shared_permission_map)
    data_entry_permission_map[Shelter] = [[
        Shelter.perms.ADD, Shelter.perms.CHANGE,
        Shelter.perms.DELETE, Shelter.perms.VIEW,
    ]]
    assign_permissions_to_group_in_migration(apps, "Shelter Data Entry", data_entry_permission_map)

    # Shelter Administration: CRUD + custom perms
    admin_permission_map = dict(shared_permission_map)
    admin_permission_map[Shelter] = [Shelter.perms]
    assign_permissions_to_group_in_migration(apps, "Shelter Administration", admin_permission_map)


def remove_shelter_groups(apps, schema_editor):
    Group = apps.get_model("auth", "Group")
    Group.objects.filter(name__in=["Shelter Data Entry", "Shelter Administration"]).delete()


